INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Zero-knowledge end-to-end encryption$q$, $q$Files are encrypted on the user's device before upload, so Internxt's servers never have access to the decryption keys or unencrypted content.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$File sharding$q$, $q$Uploaded files are split into encrypted fragments and distributed rather than stored as a single encrypted blob, adding another layer to the storage architecture.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Open-source clients$q$, $q$Internxt publishes the source code for its applications, allowing independent verification of its encryption and privacy claims.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Cross-platform apps$q$, $q$Native and web clients are available for Windows, macOS, Linux, iOS, and Android, plus a browser-based dashboard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Encrypted file sharing$q$, $q$Users can generate secure sharing links to send encrypted files to recipients who don't have an Internxt account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Internxt Send$q$, $q$A dedicated tool for quickly transferring encrypted files without needing to store them long-term in Drive.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Automatic photo backup$q$, $q$Mobile apps can automatically back up camera roll photos and videos to encrypted cloud storage.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Lifetime storage plans$q$, $q$One-time payment options give users permanent access to a fixed storage allotment without recurring subscription billing.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Business/team plans$q$, $q$Shared encrypted storage pools and basic administration for organizations that want the same privacy model across multiple users.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Additional privacy tools$q$, $q$A wider suite including a VPN product extends Internxt beyond storage into general privacy tooling.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Strong zero-knowledge, end-to-end encryption model that keeps file contents inaccessible to the provider$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Open-source client applications allow independent security verification$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$One-time lifetime storage plans offer an alternative to endless subscriptions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$EU-based (Spain) with GDPR-aligned privacy positioning$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Clean, straightforward apps across web, desktop, and mobile$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Fewer deep collaboration and productivity integrations than Google Drive or Microsoft 365$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Free tier storage is modest compared to some competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Business/enterprise feature depth is less mature than long-established storage vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Encryption model can limit certain conveniences like rich server-side file previews$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Smaller company size than major cloud storage incumbents may mean fewer support resources at scale$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Is Internxt really end-to-end encrypted?$q$, $q$Yes. Internxt encrypts files on the user's device before they are uploaded, and the company states it does not hold the decryption keys, following a zero-knowledge architecture.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Does Internxt offer a free plan?$q$, $q$Yes, Internxt provides a free tier with a limited amount of encrypted storage so new users can try the service before upgrading to a paid or lifetime plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$What is an Internxt lifetime plan?$q$, $q$Lifetime plans are one-time purchases that grant permanent access to a set amount of storage, avoiding recurring monthly or annual subscription fees.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Is Internxt open source?$q$, $q$Internxt publishes the source code for its client applications, which lets security researchers and technical users review how encryption and privacy features are implemented.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$What platforms does Internxt support?$q$, $q$Internxt offers a web dashboard along with native apps for Windows, macOS, Linux, iOS, and Android.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Private personal file storage$q$, $q$Individuals store documents, photos, and personal files with end-to-end encryption so only they can access the unencrypted contents.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Encrypted photo backup$q$, $q$Mobile users automatically back up their camera roll to encrypted cloud storage as a safeguard against device loss or damage.$q$, $q$Mobile users and families$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$One-time-payment long-term archiving$q$, $q$Users purchase a lifetime storage plan to archive large media libraries or backups without ongoing subscription costs.$q$, $q$Budget-conscious long-term users$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Small team encrypted collaboration$q$, $q$Small businesses and freelancers use business plans to share encrypted storage pools with colleagues while keeping sensitive files protected.$q$, $q$Freelancers and small teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["Limited encrypted cloud storage","Web, desktop, and mobile app access","Basic file sharing","Zero-knowledge encryption"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Essential (1TB)$q$, $q$From ~$2-4/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["1TB encrypted storage","Encrypted file sharing links","Cross-platform sync","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Premium (higher storage tiers)$q$, $q$Higher monthly rate for 2TB-3TB tiers (billed annually)$q$, $q$Monthly or annual$q$, $q$["Multiple TB of encrypted storage","Encrypted sharing and sync","Photo backup","Access to additional Internxt privacy tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$Lifetime plans$q$, $q$One-time payment, varies by storage tier$q$, $q$One-time$q$, $q$["Permanent access to a fixed storage allotment","No recurring billing","Stackable across multiple purchases","Same end-to-end encryption as subscription plans"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Internxt is a Spain-based cloud storage and privacy platform built around end-to-end encryption and a zero-knowledge architecture, meaning Internxt's own servers never hold the keys needed to read a user's files. Founded in Valencia in 2020, the company positions itself as a European, privacy-first alternative to mainstream storage providers such as Google Drive, Dropbox, and OneDrive, appealing to users who are wary of how large US-based cloud vendors handle personal data.$q$, $q$At its core is Internxt Drive, which splits every uploaded file into encrypted shards distributed across multiple locations before storage, rather than keeping a single encrypted blob on one server. The company has also expanded into a broader privacy suite that includes Internxt Send for encrypted file transfers, Internxt Meet for video calls, and a virtual private network (VPN) product, moving the brand from a single storage app toward a fuller privacy ecosystem.$q$, $q$A notable part of Internxt's identity is that its client applications are open source, letting security researchers and technically minded users inspect how encryption and key handling are implemented rather than taking the company's privacy claims purely on faith. This transparency, combined with a straightforward free tier and one-time lifetime storage plans, has made Internxt a recurring recommendation in cloud storage comparison articles focused on privacy and value rather than deep enterprise collaboration features. Because the company is headquartered in the EU, its data handling is also framed around GDPR-style privacy expectations, which resonates with users and small businesses that specifically want to keep files outside the reach of large US-based cloud vendors, and Internxt frequently contrasts its zero-knowledge architecture with providers that can technically access user files.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$who-internxt-is-for$q$, $q$Who Internxt Is For$q$, 2, ARRAY[$q$Internxt suits privacy-conscious individuals who want their personal files, photos, and documents encrypted in a way that keeps the provider itself locked out of the contents. This includes people who have grown uneasy with the data practices of larger US cloud platforms and are willing to trade some ecosystem convenience for stronger privacy guarantees and a company based in the EU under GDPR.$q$, $q$It also appeals to budget-conscious users and small teams who like the idea of paying once for storage rather than an indefinite subscription; Internxt's lifetime plans let buyers acquire a fixed amount of storage for a single upfront payment, which can be attractive for long-term personal archives, backups, or media libraries.$q$, $q$Developers and open-source enthusiasts who want to verify security claims before trusting a provider with sensitive files are a good fit too, since Internxt publishes its client source code. Freelancers and small businesses that mainly need reliable encrypted file storage and sharing, without requiring the deep third-party integrations of larger office suites, can also get solid value from the service.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams and organizations deeply embedded in Google Workspace or Microsoft 365 for real-time collaborative document editing, advanced admin controls, and extensive third-party app integrations may find Internxt's feature set comparatively narrow, since it focuses primarily on encrypted storage and sharing rather than collaborative productivity tools.$q$, $q$Users who need very large enterprise-scale deployments with dedicated account management, complex compliance certifications, or extensive single sign-on and directory integrations may find that Internxt's business tooling is less mature than that of long-established enterprise storage vendors, and should evaluate those specific requirements closely before committing.$q$, $q$People who prioritize the widest possible ecosystem of third-party app integrations, plugins, and automation tools over encryption guarantees might also be better served elsewhere, since some workflow integrations common with mainstream cloud drives are not part of Internxt's core value proposition.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Internxt Drive is the flagship product, providing zero-knowledge, end-to-end encrypted file storage and sync with client applications for web, desktop (Windows, macOS, Linux), and mobile (iOS and Android). Files are fragmented and encrypted before they leave the user's device, and the same architecture underpins file sharing links, which can be used to send encrypted files to people who don't have an Internxt account.$q$, $q$Beyond storage, the product lineup includes Internxt Send for quick encrypted file transfers, an encrypted photo backup flow for mobile devices, and privacy-adjacent tools such as a VPN, positioning Internxt as a broader privacy suite rather than a single-purpose storage app. A free tier gives new users a baseline amount of encrypted storage to try the service before upgrading.$q$, $q$For paying customers, Internxt offers tiered subscription plans (billed monthly or annually) as well as one-time lifetime storage plans that avoid recurring billing entirely. Business and team plans add shared storage pools and administration features for organizations that want the same encryption model applied across multiple users.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', $q$the-internxt-experience$q$, $q$The Internxt Experience$q$, 2, ARRAY[$q$Day to day, using Internxt feels similar to any modern cloud drive: a web dashboard for browsing and uploading files, desktop sync clients that mirror a folder on your computer, and mobile apps for accessing files and backing up photos on the go. The interface is clean and relatively uncluttered compared to some competitors, reflecting a focus on the core storage experience rather than a wide array of bolted-on productivity features.$q$, $q$The main trade-off users notice is that because Internxt cannot see file contents, certain conveniences common in non-encrypted platforms — such as server-side previews of unusual file types or deep integration with third-party productivity suites — can be more limited. Encryption and decryption happen locally, which is fundamental to the privacy model but does mean the experience is oriented around a smaller, more focused set of core actions: upload, sync, share, and back up.$q$, $q$Overall, users who choose Internxt tend to value the peace of mind of zero-knowledge encryption and open-source transparency over having every collaboration bell and whistle, and the lifetime pricing option adds a distinctive, budget-friendly angle that stands out in a market dominated by recurring subscriptions.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
