INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('daabce27-4231-4e1d-a8a8-f7d8451bc385', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$AI text-to-video generation$q$, $q$Describe a video in a text prompt and InVideo assembles a draft with stock footage, script, voiceover, and captions automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Conversational editing panel$q$, $q$Refine generated drafts by typing edit instructions instead of manipulating a traditional multi-track timeline.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Template library$q$, $q$A large collection of pre-built templates for ads, social posts, explainers, and intros that can be customized with a business's own assets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Stock media integration$q$, $q$Built-in access to stock video, image, and music libraries through partners including iStock and Storyblocks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$AI voiceover and voice cloning$q$, $q$Generate synthetic narration in multiple voices, or clone a voice for consistent narration across a series of videos.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Automatic captions and subtitles$q$, $q$Add burned-in captions automatically to improve accessibility and engagement on social platforms.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Brand kit$q$, $q$Store logos, colors, and fonts so generated and template-based videos stay consistent with a brand's identity.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Multi-platform export and resizing$q$, $q$Reformat and export a single video for different aspect ratios and platforms such as YouTube, Instagram, and TikTok.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Screen recorder$q$, $q$Capture on-screen activity directly within the platform for tutorials, demos, and walkthrough videos.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Fast way to turn a text prompt or script into a full draft video with voiceover and footage$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Large template library covers many common marketing and social video formats$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Built-in stock footage, music, and voice options reduce the need for separate licensing tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Free plan lets new users try the AI generation workflow before committing to a paid tier$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Conversational editing lowers the learning curve for people without traditional video editing experience$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Credit-based limits on AI minutes, stock downloads, and voice cloning are tracked separately and can be confusing to monitor$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Free plan exports include a watermark and only modest usage allowances$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Less suited to frame-accurate editing, color grading, or complex multi-camera projects than professional NLEs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Unused monthly credits do not roll over, which can feel wasteful for lighter-usage months$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Higher-tier plans needed for 4K export and larger AI generation and stock allowances can add up for heavy users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Is InVideo free to use?$q$, $q$InVideo offers a free plan with limited AI generation minutes and stock downloads, though exports include a watermark; paid plans remove the watermark and raise usage limits.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$What does InVideo AI actually generate?$q$, $q$Given a text prompt, InVideo AI produces a draft video combining stock footage, an AI-written script, a synthetic voiceover, background music, and captions, which can then be edited further.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$How does InVideo's credit system work?$q$, $q$Paid plans include monthly allowances for AI generation minutes, stock media downloads, voice cloning, and voiceover minutes; each is tracked separately and unused amounts do not carry over to the next month.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Can I use InVideo for professional, high-end editing?$q$, $q$InVideo is built for fast, template- and AI-assisted video production rather than frame-accurate manual editing, so users needing advanced color grading or multi-camera timelines may prefer a dedicated professional editor.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Does InVideo support team collaboration?$q$, $q$InVideo includes basic collaboration features that let teams share projects and provide feedback, alongside brand kit tools for keeping videos visually consistent across a team.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Social media content production$q$, $q$Generate short-form videos from prompts or scripts for regular posting across platforms like Instagram, TikTok, and YouTube.$q$, $q$Social media managers and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Small business advertising$q$, $q$Create polished promotional and product videos using templates or AI generation without hiring a dedicated editor.$q$, $q$Small business owners and marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Client video production at agencies$q$, $q$Speed up first drafts of recurring video formats such as testimonials, demos, and explainers before final client polish.$q$, $q$Marketing agencies and freelance video professionals$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Explainer and tutorial videos$q$, $q$Combine screen recording, AI voiceover, and captions to produce instructional or how-to content quickly.$q$, $q$Educators, trainers, and SaaS product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, $q$["Limited AI generation minutes per month","Watermarked video exports","Access to template library","Basic stock media access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Plus$q$, $q$$25/month$q$, $q$Monthly (discount available with annual billing)$q$, $q$["No watermark on exports","Commercial usage rights","AI generation minutes and voiceover minutes included","iStock asset downloads and limited voice cloning"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Max$q$, $q$$60/month$q$, $q$Monthly (discount available with annual billing)$q$, $q$["Higher AI generation minute allowance","4K export support","More iStock downloads and voice clones","Priority processing queue"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$Generative$q$, $q$$120/month$q$, $q$Monthly (discount available with annual billing)$q$, $q$["Access to premium generative video models","Highest AI generation minute and credit allowance","Large stock asset download allowance","Additional voice cloning capacity"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$InVideo started as a template-driven online video editor aimed at helping non-editors produce marketing and social clips without touching traditional editing software. Founded in 2017 and headquartered in San Francisco, the company built its early reputation on a large library of pre-made templates for ads, explainers, and social posts that users could customize with their own footage, text, and branding.$q$, $q$In recent years InVideo has repositioned itself around AI video generation. Its flagship product, InVideo AI, lets a user type a prompt describing the video they want, and the platform assembles a first draft complete with stock footage, an AI voiceover, background music, and burned-in captions. From there, a chat-style editing panel lets users refine scenes, swap clips, or adjust pacing without opening a traditional multi-track timeline.$q$, $q$This dual identity, part template library and part generative AI tool, positions InVideo alongside both older template editors and newer AI-native video startups. It competes for attention with tools like Canva's video features, Pictory, and Synthesia, while differentiating itself through the breadth of its stock media partnerships and its prompt-to-draft workflow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$who-invideo-is-for$q$, $q$Who InVideo Is For$q$, 2, ARRAY[$q$Social media managers and content creators who need to publish short-form video regularly are a core audience. InVideo's prompt-based generation and template shortcuts make it possible to turn a script or idea into a shareable clip in far less time than manual editing would take, which matters when a content calendar demands daily or weekly output.$q$, $q$Small business owners and marketers who lack design or editing skills but need polished promotional videos also fit well. Rather than hiring a video editor or learning a complex NLE, they can pick a template or describe the ad they want and let InVideo handle composition, stock footage selection, and voiceover generation.$q$, $q$Agencies and freelancers producing multiple client videos on tight deadlines can use InVideo to speed up first drafts, especially for recurring formats like product demos, testimonials, or explainer videos where a template or AI-generated starting point saves setup time before final polish.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Filmmakers, video editors, or teams that need frame-accurate control over cuts, advanced color grading, or multi-camera timelines will likely find InVideo's editor too template-driven and its AI editing panel too abstracted for precise creative work compared to professional NLEs like Premiere Pro or DaVinci Resolve.$q$, $q$Teams that want to generate large volumes of AI video without tracking usage may be frustrated by InVideo's credit system, in which AI generation minutes, stock downloads, voice cloning, and voiceover minutes are each capped separately per plan and do not roll over, requiring users to monitor several separate pools rather than one simple quota.$q$, $q$Organizations with strict data residency, on-premise, or complex enterprise asset-management requirements should evaluate carefully, since InVideo is a cloud-based SaaS product built around consumer and SMB workflows rather than deep enterprise integration or private hosting.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The centerpiece of the current product is AI text-to-video generation: a user describes a video in a prompt, and InVideo assembles a draft using stock clips, an AI-written script, synthetic voiceover, and captions, which can then be revised through conversational edit commands rather than manual timeline manipulation.$q$, $q$Alongside generation, InVideo keeps its original template library spanning ads, social posts, explainers, and intros, plus a large stock media catalog through partners like iStock and Storyblocks, AI voice cloning and text-to-speech, automatic captioning, and brand kit tools for consistent logos, fonts, and colors across videos.$q$, $q$Supporting features include one-click resizing and export for different platforms and aspect ratios, a screen recorder for tutorials and demos, and basic collaboration tools so teams can share projects and gather feedback, rounding out a workflow aimed at fast, repeatable video production rather than bespoke editing.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15dd21fe-ee11-4215-995a-79327176360a', $q$the-invideo-experience$q$, $q$The InVideo Experience$q$, 2, ARRAY[$q$Getting started is straightforward: a new user can type a prompt or pick a template and see a usable draft within minutes, which is a large part of InVideo's appeal for people who find traditional editors intimidating or too slow for their output needs.$q$, $q$Day-to-day use is shaped heavily by the credit system. The free plan exports with a watermark and modest limits, while paid tiers unlock more AI generation minutes, stock downloads, and voice cloning, but users still need to keep an eye on several separate usage pools that reset monthly and do not carry over unused amounts.$q$, $q$Overall, the experience favors speed and volume over granular control. Creators producing a steady stream of short-form or templated video tend to find it efficient, while those wanting precise manual editing may bump against the limits of the AI-assisted, prompt-driven workflow InVideo is built around.$q$]::text[], 4);
