INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Zero-touch deployment$q$, $q$Automatically enrolls and configures new Mac, iPhone, and iPad devices via Apple Business Manager or Apple School Manager as soon as they're powered on.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Policy and profile management$q$, $q$Push configuration profiles, restrictions, Wi-Fi and VPN settings, and app installs to groups of devices based on department, location, or use case.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Patch management$q$, $q$Keep macOS, iOS, and third-party applications up to date across the fleet with scheduled or policy-driven patching.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Remote lock and wipe$q$, $q$Protect data on lost or stolen devices by remotely locking or wiping them from the Jamf console.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Endpoint security (Jamf Protect)$q$, $q$Threat detection, malware defense, and compliance benchmarking designed specifically for macOS endpoints.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Identity and access (Jamf Connect)$q$, $q$Cloud identity provider integration that lets users log into a Mac with existing business credentials, including multi-factor authentication support.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Classroom and shared-device tools$q$, $q$Lock iPads into single-app mode for testing, deploy shared iPad configurations, and manage app catalogs for students and staff.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Self-service app catalog$q$, $q$Gives end users a storefront to install approved apps and software without needing IT to intervene on every request.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Inventory and reporting dashboards$q$, $q$Visibility into device compliance, OS versions, and fleet health across the whole organization.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Smart groups$q$, $q$Automatically segment devices into dynamic groups based on attributes so policies apply themselves as device conditions change.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Deep, Apple-native management that tracks Apple's own APIs and release cycles closely$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Broad product line covering device management, endpoint security, and identity in one vendor$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Strong fit for education with dedicated classroom and shared-iPad workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Established vendor with a long track record in the Apple device management space$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Zero-touch enrollment reduces manual setup work for IT teams deploying at scale$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Pricing isn't published; buyers must go through a sales process to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Primarily optimized for Apple hardware, offering less depth for Windows-heavy fleets$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Security and identity features are sold as separate add-on products rather than bundled by default$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Can be more configuration-heavy than necessary for very small teams with few devices$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Total cost of ownership can be harder to estimate upfront compared to vendors with public tiered pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$What is Jamf used for?$q$, $q$Jamf is used to enroll, configure, secure, and remotely manage Mac, iPhone, iPad, and Apple TV devices across a business, school, or government organization.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$How much does Jamf cost?$q$, $q$Jamf does not publish standard pricing; the core Jamf Pro, Protect, and Connect products are quoted by a sales team based on device count and needs, though a 14-day free trial is available. Jamf Now, aimed at teams under 25 employees, has its own simplified plan structure.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Does Jamf support Windows or Android devices?$q$, $q$Jamf includes mobile device management support for Android alongside its Apple platforms, but its feature depth and design are centered on macOS and iOS/iPadOS rather than Windows.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Is there a free trial of Jamf?$q$, $q$Yes, Jamf offers a 14-day free trial so IT teams can evaluate the platform against their own devices before purchasing.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$What's the difference between Jamf Pro, Jamf Now, and Jamf School?$q$, $q$Jamf Pro is the full enterprise management platform, Jamf Now is a simplified option for small organizations with fewer than 25 employees, and Jamf School is tailored to K-12 education with classroom-specific tools.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Enterprise Mac fleet management$q$, $q$IT departments deploy Jamf Pro to automatically enroll, configure, and patch hundreds or thousands of company-owned Mac laptops.$q$, $q$Enterprise IT administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$K-12 shared iPad management$q$, $q$Schools use Jamf School or Jamf Now to configure shared classroom iPads, lock devices into testing mode, and rotate them between students each year.$q$, $q$School district IT staff and teachers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Secure identity access on Mac$q$, $q$Organizations pair Jamf Connect with Jamf Pro so employees can sign into their Mac using existing cloud identity credentials and MFA.$q$, $q$Security and identity teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Small business Apple device oversight$q$, $q$Small companies with fewer than 25 employees use Jamf Now to keep a lightweight inventory of Apple devices and enforce basic security settings without a dedicated IT department.$q$, $q$Small business owners and office managers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Jamf Now$q$, $q$Contact for pricing$q$, $q$Per device, monthly$q$, $q$["Aimed at organizations with fewer than 25 employees","Basic device inventory and configuration","Malware protection","Supports macOS, iOS, iPadOS, and tvOS"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Jamf for Mac$q$, $q$Contact for pricing$q$, $q$Per device, annual$q$, $q$["Full macOS device management","Endpoint security and vulnerability management","Identity and access management","Zero Trust Network Access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Jamf for Mobile$q$, $q$Contact for pricing$q$, $q$Per device, annual$q$, $q$["iOS, iPadOS, and Android device management","Mobile threat defense","Zero Trust access","App and configuration deployment"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Jamf Business Plan (bundle)$q$, $q$Contact for pricing$q$, $q$Per device, annual$q$, $q$["Combines Jamf Pro, Protect, and Connect","Discounted vs. purchasing modules separately","Full device management, security, and identity","Suited to larger enterprise deployments"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jamf is a device management and endpoint security platform built specifically around Apple's ecosystem. Founded in 2002 in Minneapolis, Minnesota, the company grew out of the early days of enterprise Mac adoption and has since become one of the most recognized names in Apple-focused IT, serving businesses, schools, and government agencies that need to deploy, configure, and secure fleets of Mac, iPhone, iPad, and Apple TV devices at scale.$q$, $q$The core product, Jamf Pro, lets IT and security teams enroll devices automatically, push configuration profiles and apps, enforce compliance policies, and remotely wipe or lock lost hardware. Around that core, Jamf has built out a broader portfolio that includes Jamf Protect for endpoint security and threat detection, Jamf Connect for identity and single sign-on, and Jamf Now, a simplified plan aimed at very small organizations that just need basic device oversight without a full IT department.$q$, $q$Because it is purpose-built for Apple rather than a generic cross-platform MDM bolted onto Apple support, Jamf tends to track Apple's own release cycles and management APIs closely, which is a large part of its appeal to organizations that are Mac- and iOS-heavy. It is generally positioned as enterprise software: pricing is quote-based, deployments often involve a sales conversation, and the product is aimed at IT departments rather than individual consumers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$who-jamf-is-for$q$, $q$Who Jamf Is For$q$, 2, ARRAY[$q$Jamf is best suited to organizations that have standardized, or are standardizing, on Apple hardware and need centralized control over that fleet. IT administrators at mid-size and large companies managing hundreds or thousands of Mac laptops and iPhones are the clearest fit, particularly when compliance, security policy enforcement, and zero-touch deployment are priorities.$q$, $q$Education is another core audience: schools and districts use Jamf (often via Jamf School or Jamf Now, depending on size) to manage shared iPads in classrooms, restrict apps during testing, and simplify device handoffs between students each year. Healthcare and government bodies with strict compliance and data-protection requirements also make up a meaningful share of Jamf's customer base, given the platform's security and reporting capabilities.$q$, $q$Smaller businesses with a lighter Apple footprint can also use Jamf, typically through Jamf Now, which is explicitly marketed at organizations with fewer than 25 employees and packages a simpler set of controls than the full Jamf Pro suite. Managed service providers supporting multiple Apple-centric clients are another common user group, since Jamf's tooling is designed to scale across many devices and locations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations with a mixed or Windows-heavy device fleet are generally not the ideal audience for Jamf. While Jamf does support mobile device management for Android alongside Apple platforms, its depth of feature coverage, integrations, and product design are all oriented around Apple hardware, so a company managing mostly Windows PCs will typically get more value from a cross-platform unified endpoint management tool.$q$, $q$Very small teams and solo operators without dedicated IT staff may also find Jamf to be more than they need. The full Jamf Pro platform assumes a level of policy configuration, profile management, and ongoing administration that can feel heavy for a handful of devices, and the lack of published, self-serve pricing means smaller buyers have to go through a sales process to even get a quote.$q$, $q$Budget-constrained organizations that want transparent, publicly listed pricing should also weigh their options carefully. Jamf's core enterprise products are quoted individually by a sales team, and add-on modules like Jamf Protect and Jamf Connect are priced and sold separately from the base management plan, which can make total cost of ownership harder to estimate upfront compared to vendors with simple published tiers.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Jamf Pro provides zero-touch deployment through Apple Business Manager and Apple School Manager, automatically enrolling new devices and applying configuration profiles, restrictions, and app installs the moment they're powered on. Administrators can group devices by department, location, or use case and apply policies, patch updates, and compliance checks to those groups without touching each machine individually.$q$, $q$Security and identity are handled through companion products: Jamf Protect adds endpoint detection and response, malware defense, and compliance benchmarking tailored to macOS, while Jamf Connect layers on cloud identity provider integration so users can log into a Mac with the same credentials used for other business apps, including support for password sync and multi-factor authentication.$q$, $q$For education, Jamf School (and Jamf Now for smaller teams) offers classroom-management features such as locking iPads into a single app during a test, pushing out shared iPad configurations, and self-service app catalogs students and staff can use to install approved software. Across the product line, Jamf also provides reporting and inventory dashboards, remote lock and wipe for lost or stolen devices, and patch management to keep operating systems and third-party apps current.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$the-jamf-experience$q$, $q$The Jamf Experience$q$, 2, ARRAY[$q$Day to day, Jamf is administered through a web-based console where IT staff build policies, configuration profiles, and smart groups that automatically sort devices based on attributes like OS version or department. Because it's built specifically for Apple's management frameworks, most core workflows map closely to how Apple expects devices to be provisioned, which reduces the friction that generic MDM tools sometimes hit when Apple changes its APIs.$q$, $q$New customers typically start with a sales conversation and a 14-day free trial to test the platform against their own device fleet before committing, since pricing isn't published on the website. Onboarding for larger deployments often involves Jamf's own professional services or a certified partner, particularly when migrating from another MDM or integrating with existing identity and security tooling.$q$, $q$End users mostly experience Jamf indirectly, through self-service app catalogs, single sign-on prompts from Jamf Connect, or restrictions applied to a work iPhone or classroom iPad, rather than interacting with the admin console directly. For the IT teams running it, the overall experience is generally described as powerful but geared toward organizations willing to invest time in policy configuration and, for larger rollouts, a supporting budget for premium support or professional services.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
