INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Brand Voice$q$, $q$Trains Jasper on a company's existing content and guidelines so generated copy consistently matches established tone, style, and terminology.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Knowledge Base$q$, $q$Stores company facts, product details, and approved messaging that Jasper references automatically when generating content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Campaigns & Workflows$q$, $q$Coordinates multi-asset marketing campaigns—ads, emails, landing pages, and more—from a single brief.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Document Editor$q$, $q$A long-form writing workspace for blog posts and articles, with inline AI commands for editing, expanding, and rewriting text.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Chat Assistant$q$, $q$A conversational interface for quick content requests, brainstorming, and ad hoc writing tasks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Template Library$q$, $q$Pre-built prompts for common marketing formats such as product descriptions, ad copy, social captions, and email subject lines.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Jasper Art$q$, $q$AI image generation for creating visuals and graphics alongside written content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$SEO Mode$q$, $q$Incorporates keyword and on-page optimization guidance into generated content for search-focused writing.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Browser Extension$q$, $q$Brings Jasper's writing assistance directly into external websites, CMSs, and web forms.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$API Access$q$, $q$Lets teams connect Jasper's content generation capabilities into their own internal tools and workflows.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Strong brand-voice and knowledge-base tools help keep content consistent across multiple writers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Purpose-built for marketing workflows, including campaigns spanning ads, email, and landing pages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Broad template library speeds up common content formats$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Team-oriented collaboration and seat management suited to marketing departments and agencies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Combines writing, image generation, and SEO guidance in one workspace$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$No permanent free plan, only a time-limited free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Pricing is oriented around ongoing team use, which can be costly for occasional or solo writers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Business-tier pricing is custom and not transparent upfront$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Less suited to general-purpose chat, coding, or long-form creative writing than dedicated tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Getting the most value requires upfront setup of Brand Voice and the knowledge base$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Does Jasper offer a free plan?$q$, $q$Jasper does not offer a permanent free plan, but it provides a limited-time free trial that lets new users test its features before subscribing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$How much does Jasper cost?$q$, $q$Jasper's paid plans start with a Creator tier priced from around $39 per month when billed annually, with a Pro tier and a custom-priced Business tier available for larger teams with more advanced needs.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Who is Jasper designed for?$q$, $q$Jasper is designed primarily for marketing teams, agencies, and content-heavy businesses that need consistent, on-brand copy produced by multiple writers, though individual creators can use it as well.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Can Jasper generate images as well as text?$q$, $q$Yes, Jasper includes an image generation feature called Jasper Art, alongside its text-generation and campaign tools, so teams can produce visuals within the same platform.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Does Jasper integrate with other marketing tools?$q$, $q$Jasper offers a browser extension for writing on external sites, an SEO mode that can incorporate keyword guidance, and API access for connecting its content generation into other internal tools and workflows.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Scaling in-house marketing content$q$, $q$Marketing departments use Jasper's Brand Voice and templates to produce a higher volume of blog posts, ads, and emails while keeping messaging consistent across writers.$q$, $q$In-house marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Managing multi-client content production$q$, $q$Agencies maintain separate brand profiles and voice settings for each client, allowing writers to switch between accounts without losing brand consistency.$q$, $q$Marketing and content agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Generating product and catalog copy$q$, $q$E-commerce teams use Jasper's templates to draft product descriptions, category copy, and promotional text at scale.$q$, $q$E-commerce and retail businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Coordinating enterprise campaign launches$q$, $q$Larger organizations use Jasper's campaign tools and knowledge base to align copy across ads, landing pages, and email for a single product or brand launch.$q$, $q$Enterprise marketing organizations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Creator$q$, $q$From $39/month$q$, $q$Billed annually (higher if billed monthly)$q$, $q$["AI writing assistant and document editor","Access to core templates","Single Brand Voice","Chat assistant for quick content requests"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Pro$q$, $q$From $59/month$q$, $q$Billed annually (higher if billed monthly)$q$, $q$["Multiple Brand Voices","Campaign and workflow tools","Team seats and collaboration","SEO mode integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Business$q$, $q$Custom pricing$q$, $q$Custom/annual contract$q$, $q$["Custom word/seat packages","Advanced admin and security controls","Dedicated onboarding and support","API access for internal integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jasper (originally launched as Conversion.ai, then briefly Jarvis) is a generative AI platform built specifically for marketing and brand content teams. Rather than positioning itself as a general-purpose chatbot, Jasper focuses on helping companies produce on-brand copy, campaigns, and creative assets at scale, using large language models tuned with company-specific voice, style, and knowledge inputs.$q$, $q$The platform combines a chat-style assistant, a document editor, campaign and workflow tools, and image generation into one workspace, so marketing teams can move from a content brief to finished, brand-consistent copy without switching tools. Jasper also integrates with SEO tools and browser extensions so writers can generate copy directly inside CMSs, ad platforms, and web forms.$q$, $q$Since its rebrand from Jarvis to Jasper, the company has shifted from being a broad AI-writing tool for solo creators toward an enterprise-oriented "AI marketing copilot," emphasizing brand governance, team collaboration, and integration with a company's existing marketing stack rather than raw word-count generation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$who-jasper-is-for$q$, $q$Who Jasper Is For$q$, 2, ARRAY[$q$Jasper is best suited to marketing teams, agencies, and content-heavy businesses that need to produce a high volume of on-brand copy across channels such as blogs, ads, email, and social media. Its Brand Voice and knowledge-base features are particularly valuable for organizations juggling multiple writers who need to sound consistent.$q$, $q$In-house marketing departments at mid-size and larger companies are a strong fit, since Jasper's team seats, approval workflows, and admin controls are designed for collaborative environments rather than solo use. Agencies managing content for several clients also benefit from being able to maintain separate brand profiles and voice settings per account.$q$, $q$Freelance copywriters, solopreneurs, and small businesses can still use Jasper productively for blog posts, product descriptions, and ad copy, but they will get the most value if they're producing content regularly enough to justify a recurring subscription rather than writing only occasionally.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Jasper is not the most economical choice for people who only need occasional help with writing, since there is no permanent free plan and pricing is built around regular, ongoing use by a team rather than a single writer with light needs. Casual or infrequent users may find cheaper or free general-purpose AI chat tools sufficient.$q$, $q$Developers and technical teams looking for a raw API to embed language-model capability into their own products may prefer working directly with a foundation-model provider, since Jasper's API and pricing are structured around its marketing workflows rather than being a low-level, general-purpose completion endpoint.$q$, $q$Users who mainly want long-form creative fiction, highly technical documentation, or code generation will likely be better served by tools built for those specific use cases, since Jasper's templates, workflows, and brand controls are optimized for marketing and business copy rather than these other content types.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Jasper is its Brand Voice system, which lets teams feed in existing content and style guidelines so generated copy matches a company's established tone, terminology, and messaging rules. This is paired with a knowledge base of company facts, product details, and approved claims that Jasper can pull from when writing, reducing the need for writers to re-explain context in every prompt.$q$, $q$Jasper's editor and campaign tools support end-to-end content production, from long-form documents and blog posts to multi-asset marketing campaigns spanning ads, emails, and landing pages. A chat-style assistant handles quick requests and brainstorming, while a large library of templates covers common marketing formats such as product descriptions, ad variations, and social captions.$q$, $q$Additional capabilities include Jasper Art for AI image generation, an SEO mode that can incorporate keyword and competitor guidance, a browser extension for writing directly on external websites and forms, and API access for connecting Jasper's content generation into other internal tools or workflows.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$the-jasper-experience$q$, $q$The Jasper Experience$q$, 2, ARRAY[$q$Using Jasper typically starts with setting up a Brand Voice profile and, for teams, a shared knowledge base, which meaningfully improves output quality compared to using a blank, generic AI assistant. Once configured, day-to-day use feels like a mix of a document editor and a chat assistant, with templates available to jump-start specific content types.$q$, $q$Teams generally find the collaborative features—shared brand settings, multiple seats, and consistent voice across writers—to be Jasper's clearest advantage over general-purpose AI chat tools, especially when several people are producing content under the same brand. The learning curve is modest, though getting the most out of Brand Voice and the knowledge base takes some initial setup time.$q$, $q$Because Jasper is priced and packaged around ongoing, team-based use, the overall experience is oriented toward organizations treating AI-assisted content as a continuous part of their marketing operation, rather than a one-off tool for occasional writing tasks.$q$]::text[], 4);
