INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Job posting & syndication$q$, $q$Post a single requisition out to free job boards and premium listings, cutting down on manual posting to each site individually.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Applicant tracking & pipelines$q$, $q$Centralize every application into configurable pipeline stages, with tagging and filtering to compare candidates side by side.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Configurable workflow automation$q$, $q$Automate reminders, task assignments, and candidate routing so hiring managers know what to do next at each stage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$AI-powered candidate matching$q$, $q$Surface applicants that most closely match a role's requirements, available on the Plus and Pro plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Structured interviews & assessments$q$, $q$Standardize candidate evaluation with interview guides, scorecards, and assessment integrations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Offers & eSignature$q$, $q$Generate and send offer letters with built-in electronic signature support to speed up the closing stage of hiring.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Reporting & custom report builder$q$, $q$Track hiring metrics with standard dashboards, plus a custom report builder and workflow reporting on the Pro plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Career site & branded job pages$q$, $q$Present open roles on a branded careers page so candidates can browse and apply directly.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Integration marketplace$q$, $q$Connect to background check providers, assessments, calendars, HRIS systems, and LinkedIn Recruiter.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Email templates & communication tools$q$, $q$Keep candidate outreach consistent with reusable email templates tied to pipeline stages.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Flat-fee pricing with unlimited users, so more hiring managers can be added without extra per-seat cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Free syndication to major job boards simplifies posting the same role in multiple places$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Fast setup and an approachable interface compared to enterprise ATS platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Broad integration marketplace covering background checks, assessments, and HRIS tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Positive reputation for customer support, especially on higher-tier plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Active job posting caps on lower tiers can force an upgrade sooner than expected$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Interface and workflow builder feel less modern than some newer ATS competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Deeper reporting, automation, and AI matching are gated behind the Plus and Pro plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Pricing rises quickly moving from the Hero plan to Plus and Pro tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Not well suited to enterprise-scale, multi-country, or very high-volume agency recruiting$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$What is JazzHR used for?$q$, $q$JazzHR is an applicant tracking system used by small and mid-sized businesses to post jobs, screen and track candidates, coordinate hiring managers, and manage offers in one platform.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Does JazzHR offer a free trial?$q$, $q$JazzHR has historically offered a free trial period so businesses can test the platform before committing to a paid plan; current trial availability and length should be confirmed on jazzhr.com.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$How much does JazzHR cost?$q$, $q$JazzHR is sold in three annually billed tiers, Hero, Plus, and Pro, with prices ranging from roughly $1,000/year up to over $5,500/year depending on job volume and features; monthly billing is available at a higher rate.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Is JazzHR good for small businesses?$q$, $q$Yes, JazzHR is specifically built for small and mid-sized businesses, offering an unlimited-user model and job board syndication that make it easier for lean teams to run a structured hiring process.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Does JazzHR integrate with other tools?$q$, $q$JazzHR offers an integration marketplace connecting to background check vendors, assessment providers, calendar tools, HRIS platforms, and LinkedIn Recruiter, among others.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Replacing spreadsheets and email for hiring$q$, $q$A small business with no formal ATS moves candidate tracking, resumes, and interview feedback out of inboxes and spreadsheets into a single pipeline.$q$, $q$Small businesses hiring for the first time with a dedicated system$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Coordinating hiring across many hiring managers$q$, $q$A company with several department heads involved in hiring gives each of them pipeline access without paying for extra recruiting seats.$q$, $q$Growing companies with distributed, non-recruiter hiring managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Standardizing hiring as the company scales$q$, $q$An HR team introduces structured interview scorecards and configurable workflows to keep hiring consistent as job volume grows.$q$, $q$Scaling SMBs formalizing their hiring process$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Speeding up offers with eSignature$q$, $q$A hiring team generates offer letters and collects signatures directly in the platform to shorten time-to-hire in a competitive market.$q$, $q$Hiring teams on the Pro plan closing candidates quickly$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Hero$q$, $q$$1,000/year (billed annually)$q$, $q$Annual (monthly billing available at a higher rate)$q$, $q$["Starting at 3 active jobs, additional jobs available at extra cost","Applicant tracking system","Job board syndication including premium listings","Email message templates","LinkedIn Recruiter integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Plus$q$, $q$$3,480/year (billed annually)$q$, $q$Annual (monthly billing available at a higher rate)$q$, $q$["Up to 200 active jobs","Everything in Hero","AI-powered candidate matching","Structured interviews and assessments","Configurable task automation and standard reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Pro$q$, $q$$5,508/year (billed annually)$q$, $q$Annual (monthly billing available at a higher rate)$q$, $q$["Everything in Plus","Offers and eSignature","Advanced visual reporting and custom report builder","Workflow reports","All-access customer support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$JazzHR is a cloud-based applicant tracking system (ATS) designed to help small and mid-sized businesses run a structured hiring process without the cost or complexity of enterprise recruiting software. Originally launched in 2009 as The Resumator, the company rebranded to JazzHR and is now part of Employ Inc., the group that also owns Jobvite and Lever, positioning JazzHR as the SMB-focused entry point in that portfolio.$q$, $q$At its core, JazzHR lets hiring teams post open roles to free and premium job boards, track applicants through customizable pipeline stages, coordinate feedback among hiring managers, and move candidates toward offers, all from a single dashboard. It bundles job syndication, collaborative screening, interview scheduling, reporting, and offer management into one flat-fee product rather than charging per recruiter seat.$q$, $q$JazzHR's pitch is straightforward: replace ad hoc hiring conducted over spreadsheets, inboxes, and job board logins with a centralized, unlimited-user system that a lean HR team or even a single hiring manager can set up quickly. It competes with other SMB ATS tools such as BambooHR's hiring module, Breezy HR, and Workable, rather than with large enterprise HCM suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$who-jazzhr-is-for$q$, $q$Who JazzHR Is For$q$, 2, ARRAY[$q$JazzHR is aimed squarely at small and mid-sized businesses that need a real applicant tracking system but don't have a dedicated recruiting operations team or enterprise HR budget. Companies hiring anywhere from a handful to a few hundred roles a year, without deep in-house recruiting infrastructure, are the core audience.$q$, $q$It suits organizations where multiple people, HR generalists, department heads, office managers, need to weigh in on candidates but shouldn't each require a separate paid recruiting seat. Because JazzHR prices by plan tier rather than per user, growing teams that want to loop in many hiring managers without renegotiating a contract tend to find it a good fit.$q$, $q$It also works well for businesses that rely heavily on free job board distribution and want an easier way to manage the resulting flood of applications, plus companies that value straightforward setup over deep configurability, since JazzHR favors accessible workflows over the granular customization found in larger platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex, multi-country hiring, deep compliance requirements, or the need for tight integration with a broader HCM stack will likely outgrow JazzHR quickly. Sister products under Employ Inc., such as Lever or Jobvite, are built for that scale and sophistication, and are the more natural fit once hiring volume and organizational complexity grow substantially.$q$, $q$Staffing agencies and recruiters managing very high candidate and requisition volumes may also find JazzHR's job posting caps and plan-tier limits restrictive, since the product is priced and packaged around SMB hiring volumes rather than high-throughput agency recruiting.$q$, $q$Teams expecting a highly modern, AI-first sourcing and automation experience, or extensive built-in analytics and customization out of the box, may find JazzHR's interface and feature depth more basic than newer entrants in the ATS space, particularly on the lower pricing tiers where reporting and automation are limited.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$JazzHR's foundation is job posting and syndication: a single job requisition can be pushed out to free job boards and premium listings, reducing the manual work of posting separately to each site. Applicant tracking then centralizes every resume and application into configurable pipeline stages, with tools for tagging, filtering, and comparing candidates side by side, plus email templates to keep candidate communication consistent.$q$, $q$On top of the core pipeline, JazzHR adds collaboration and structure: configurable task automation and workflows route candidates and reminders to the right hiring manager, structured interview guides and scorecards standardize evaluation, and AI-powered candidate matching (available on higher tiers) helps surface applicants who most closely fit a role's requirements.$q$, $q$Later stages of hiring are covered by offer letters with eSignature support, plus reporting that ranges from standard dashboards to a custom report builder and workflow-level analytics on the Pro plan. An integration marketplace connects JazzHR to background check providers, assessment tools, calendars, HRIS platforms, and LinkedIn Recruiter, letting it slot into an existing hiring stack rather than replacing every tool a company already uses.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$the-jazzhr-experience$q$, $q$The JazzHR Experience$q$, 2, ARRAY[$q$New users generally describe JazzHR's setup as fast relative to enterprise ATS platforms: creating a job requisition, defining pipeline stages, and inviting an unlimited number of hiring managers can be done without lengthy implementation projects, which is a big part of its appeal for lean teams standing up their first real hiring process.$q$, $q$Day to day, hiring teams spend most of their time in the candidate pipeline, moving applicants between stages, leaving feedback, and triggering emails or interview requests. Reviewers on sites like G2 and Capterra consistently highlight ease of use and the value of unlimited users as strengths, while noting that the interface can feel dated compared to newer ATS entrants and that deeper reporting or automation often requires an upgrade to a higher plan.$q$, $q$Customer support is frequently cited as responsive, particularly on the higher-tier plans that include priority or all-access support, and the overall sentiment across review platforms skews positive for its intended audience: small and mid-sized businesses that want a dependable, no-frills ATS rather than a highly configurable enterprise platform.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
