INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Intelligent code completion$q$, $q$Context-aware suggestions based on the actual semantics of the code, not just text matching, covering variables, methods, and framework-specific APIs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Automated refactoring$q$, $q$Safe rename, extract method/variable, inline, and move refactorings that update all references across the project automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Built-in debugger$q$, $q$A visual step-through debugger with breakpoints, watches, and evaluate-expression support for Java, Kotlin, and other JVM languages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Version control integration$q$, $q$Native Git support plus additional VCS integrations, including diff viewers, commit history, and merge conflict resolution inside the IDE.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Database tools (Ultimate)$q$, $q$A built-in SQL client for browsing schemas, running queries, and editing data across popular relational and some NoSQL databases.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Framework support (Ultimate)$q$, $q$Deep integration with Spring, Jakarta EE, and other enterprise frameworks, including navigation between configuration and code.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Docker and Kubernetes integration (Ultimate)$q$, $q$Manage containers and inspect Kubernetes resources without leaving the IDE, useful for teams working with containerized services.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$JetBrains AI Assistant$q$, $q$AI-powered code completion, chat, and code explanation integrated directly into the editor, available as an add-on.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Plugin marketplace$q$, $q$A large catalog of community and JetBrains-built plugins for extending language support, tooling, and themes.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Built-in terminal and decompiler$q$, $q$An embedded terminal for shell commands and a bytecode decompiler for inspecting compiled Java classes without leaving the IDE.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Deep, semantic-aware code intelligence that makes large-scale refactoring safer and faster$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Fully-featured free Community edition covers core Java and Kotlin development at no cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Extensive built-in tooling (debugger, VCS, terminal, database client) reduces the need for external tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Consistent experience and shortcuts shared across other JetBrains IDEs, easing multi-language teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Strong first-party support for enterprise Java frameworks in the Ultimate edition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Ultimate edition requires an ongoing paid subscription for framework, database, and profiling features$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Higher memory and CPU usage than lightweight text editors, especially on large projects$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Steeper learning curve for developers new to JetBrains' interface conventions and dense feature set$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Primary value proposition is centered on JVM languages, offering less benefit for non-Java/Kotlin stacks$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Startup and indexing time can be noticeably slower than minimalist editors when opening large codebases$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Is IntelliJ IDEA free?$q$, $q$Yes. The Community edition is free and open source and covers core Java, Kotlin, and Groovy development. The Ultimate edition, which adds enterprise framework, database, and web development tooling, requires a paid subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$What is the difference between IntelliJ IDEA Community and Ultimate?$q$, $q$Community focuses on core JVM language development (Java, Kotlin, Groovy) with Git and basic debugging support. Ultimate adds database tools, enterprise framework support (Spring, Jakarta EE), application server integration, profilers, and full-stack web development features.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Does IntelliJ IDEA support languages other than Java?$q$, $q$Yes. It has strong built-in support for Kotlin, Groovy, and Scala, and can support additional languages like JavaScript, TypeScript, Python, and SQL through bundled or installable plugins, particularly in the Ultimate edition.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Can I try IntelliJ IDEA Ultimate before paying?$q$, $q$JetBrains offers a free trial period for the Ultimate edition so developers and teams can evaluate its additional tooling before committing to a subscription.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Is Android Studio the same as IntelliJ IDEA?$q$, $q$No, but they are closely related. Android Studio is Google's official Android development environment, and it is built on the same underlying IntelliJ platform that powers IntelliJ IDEA.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Enterprise Java backend development$q$, $q$Teams building Spring Boot or Jakarta EE services use Ultimate's framework-aware navigation, database tools, and application server integration to move faster on large backend codebases.$q$, $q$Enterprise backend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Kotlin application development$q$, $q$Developers writing Kotlin for server-side, Android, or multiplatform projects rely on IntelliJ IDEA's first-party Kotlin support, since JetBrains also created and maintains the Kotlin language.$q$, $q$Kotlin and Android developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Learning Java and Kotlin$q$, $q$Students and self-taught developers use the free Community edition to write, debug, and refactor code while learning core Java or Kotlin concepts without any licensing cost.$q$, $q$Students and self-learners$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Large-codebase refactoring and maintenance$q$, $q$Teams maintaining large, long-lived JVM codebases use IntelliJ IDEA's safe automated refactorings and project-wide code analysis to make structural changes with lower risk of breakage.$q$, $q$Engineering teams maintaining legacy or large-scale JVM systems$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Community$q$, $q$Free$q$, $q$N/A$q$, $q$["Core Java, Kotlin, and Groovy development","Built-in debugger and test runner integration","Git and other VCS support","Open source, no license required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Ultimate (Individual)$q$, $q$From $19.90/month or $199/year$q$, $q$Monthly or annual$q$, $q$["Everything in Community","Enterprise framework support (Spring, Jakarta EE)","Database tools and SQL client","Docker/Kubernetes integration and profilers","Free trial available before purchase"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Ultimate (Organizations)$q$, $q$Contact JetBrains for team pricing$q$, $q$Annual$q$, $q$["All Ultimate features for teams","Centralized license management","Volume-based pricing tiers","Priority support options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$JetBrains IntelliJ IDEA is the company's flagship integrated development environment, built primarily for Java and Kotlin development. JetBrains, founded in 1999 and headquartered in Prague, Czech Republic, built its reputation on deeply intelligent, IDE-first tooling, and IntelliJ IDEA remains the product that defined that approach: an editor that understands the structure and semantics of your code rather than just its text.$q$, $q$IntelliJ IDEA ships in two editions. The Community edition is free and open source, covering core Java, Kotlin, and Groovy development along with Git integration, a solid debugger, and JUnit support. The Ultimate edition is a paid, commercial product that adds framework-specific tooling (Spring, Jakarta EE, and others), full-stack web development support, database tools, application server integrations, and profilers aimed at professional and enterprise teams.$q$, $q$Because IntelliJ IDEA's underlying platform also powers other JetBrains IDEs (PyCharm, WebStorm, PhpStorm, and Android Studio, which is built on the IntelliJ platform), its plugin architecture, keymaps, and UI conventions are widely recognized across the JVM and broader developer ecosystem, making it a common reference point for how a modern IDE should behave.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$who-intellij-idea-is-for$q$, $q$Who IntelliJ IDEA Is For$q$, 2, ARRAY[$q$IntelliJ IDEA is built for professional Java and Kotlin developers, from individual contributors to large engineering organizations, who want an IDE that actively assists with navigation, refactoring, and error detection across sizable codebases rather than a bare-bones text editor.$q$, $q$Backend and enterprise teams working with Spring, Jakarta EE, microservices, or containerized applications are a core audience for the Ultimate edition, since it bundles the framework awareness, application server support, and database tooling those stacks typically require.$q$, $q$Students, hobbyists, and open-source contributors are well served by the free Community edition, which covers everyday Java and Kotlin work without a subscription, making it a common starting point for learning the language ecosystem before a team upgrades to Ultimate for commercial projects.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Developers who want a lightweight, fast-launching editor for quick edits or polyglot scripting across many small projects may find IntelliJ IDEA heavier than they need; editors like VS Code or Sublime Text start faster and use fewer system resources for casual work.$q$, $q$Teams whose primary language isn't Java, Kotlin, or another JVM-adjacent language may not get proportional value from Ultimate's price, since much of its premium tooling (application servers, JVM profilers, enterprise framework support) is oriented around that ecosystem rather than general-purpose scripting or systems programming.$q$, $q$Solo developers or small teams on a tight budget who only occasionally need Ultimate-only capabilities may find the ongoing subscription cost hard to justify against the fully free Community edition or other free IDEs, especially if their projects don't touch the specific frameworks Ultimate targets.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, IntelliJ IDEA offers context-aware code completion, on-the-fly code analysis, and automated refactorings (rename, extract method, inline, and more) that operate on a real semantic model of the code rather than plain text, reducing manual cleanup after structural changes.$q$, $q$Built-in tooling covers much of the daily developer workflow out of the box: a visual debugger, integrated Git and other VCS support, a built-in terminal, a bytecode decompiler, and test runner integrations for JUnit, TestNG, and similar frameworks, all without needing separate standalone tools.$q$, $q$The Ultimate edition extends this with database tools for querying and managing SQL and NoSQL databases directly in the IDE, support for major web and enterprise frameworks, Docker and Kubernetes integration, performance profilers, and JetBrains AI Assistant for AI-powered code completion, chat, and explanation, layered on top of everything Community already provides.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$the-intellij-idea-experience$q$, $q$The IntelliJ IDEA Experience$q$, 2, ARRAY[$q$Day-to-day use centers on IntelliJ IDEA's project indexing, which scans a codebase up front so that navigation features like Find Usages, Go to Declaration, and safe refactoring work instantly across even large, multi-module projects rather than relying on simple text search.$q$, $q$The interface is dense with functionality, and new users typically spend some time customizing keymaps, themes, and the plugin set through the JetBrains Marketplace; long-time users of Eclipse, Visual Studio, or Vim can install keymap plugins to keep familiar shortcuts, which softens the learning curve considerably.$q$, $q$Licensing and updates are managed through the JetBrains Toolbox App, which handles installation, version updates, and subscription status across all JetBrains IDEs on a machine, so teams standardizing on IntelliJ IDEA alongside other JetBrains products get a single, consistent update and license-management experience.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
