INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Incident management$q$, $q$Queue-based incident tracking with prioritization, escalation paths, and major incident workflows for coordinating response across teams.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Change management$q$, $q$Configurable change request workflows with risk assessment and approvals to help reduce failed or unauthorized changes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Problem management$q$, $q$Root-cause tracking that links recurring incidents to underlying problems for longer-term resolution.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Asset and configuration management$q$, $q$Built-in CMDB functionality to track hardware, software, and their relationships to incidents, changes, and requests.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Self-service help center$q$, $q$A branded customer portal where employees or customers submit requests through structured forms across multiple service projects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Knowledge base integration$q$, $q$Confluence-powered knowledge base surfaced in the portal so requesters can self-resolve before submitting a ticket.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$SLAs and automation rules$q$, $q$Configurable service-level agreements paired with no-code automation for routing, escalation, and notifications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Jira Software integration$q$, $q$Native linking between service tickets and Jira Software issues so engineering and support work stay connected.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$AI-assisted support$q$, $q$Atlassian Intelligence features for ticket summarization, suggested replies, and virtual-agent style request deflection.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Service project templates$q$, $q$Pre-built templates for IT, HR, legal, and general business service desks to speed up initial setup.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Deep native integration with Jira Software makes it a strong fit for teams already using Jira for engineering work$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Covers a broad set of ITSM disciplines (incident, problem, change, asset management) in one product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Confluence-backed knowledge base and self-service portal can reduce repetitive ticket volume$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Flexible workflow and automation configuration supports processes beyond IT, including HR and legal$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Free tier and per-agent pricing make it accessible to small teams before scaling to larger paid plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Initial setup and configuration (workflows, permission schemes, SLAs) can be complex for teams new to Jira$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Value is strongest when paired with other Atlassian products, which is a limitation for non-Atlassian shops$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Per-agent pricing can become costly as support teams grow, especially on Premium and Enterprise tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Interface and terminology carry over Jira's project-management conventions, which can feel unfamiliar to pure support staff$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Not purpose-built for external, high-volume customer support compared to dedicated help desk or contact-center tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$What is Jira Service Management used for?$q$, $q$It's used for IT service management tasks such as incident, problem, change, and asset management, as well as general service desk functions for teams like HR, legal, and facilities.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Is Jira Service Management free?$q$, $q$Yes, there is a free plan for small teams (typically up to 3 agents) with core service desk functionality; larger teams move to paid Standard, Premium, or Enterprise plans billed per agent.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Do I need Jira Software to use Jira Service Management?$q$, $q$No, JSM can run as a standalone service project, but it integrates natively with Jira Software issues, so teams already using Jira for development get added benefits from linking support and engineering work.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Does Jira Service Management support ITIL processes?$q$, $q$Yes, its incident, problem, and change management workflows are designed to align with common ITIL practices, including change approvals and post-incident reviews.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Can non-IT teams use Jira Service Management?$q$, $q$Yes, Atlassian provides service project templates for HR, legal, facilities, and other business teams so they can run their own request queues and portals on the same platform.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$IT help desk and incident response$q$, $q$Centralize employee IT requests and incidents into prioritized queues with SLAs, escalation paths, and links to related Jira Software work.$q$, $q$IT support and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Change and release management$q$, $q$Route change requests through approval workflows and risk assessments before deployments to reduce failed or unauthorized changes.$q$, $q$IT operations and DevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$HR and internal business service desks$q$, $q$Run structured request portals for onboarding, policy questions, and internal requests outside of IT using the same platform and admin model.$q$, $q$HR, legal, and facilities teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Asset and configuration tracking$q$, $q$Maintain a lightweight CMDB that links hardware and software assets to incidents and changes for better root-cause visibility.$q$, $q$IT asset managers and support engineers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Up to 3 agents","Self-service portal and email/chat intake","Confluence-powered knowledge base","Basic ITSM, HR, and other service templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Standard$q$, $q$From $20/agent/month$q$, $q$per agent, monthly or annual$q$, $q$["Scales up to 20,000 agents and unlimited customers","Custom-branded help center","Unlimited email notifications","Audit logs and multi-region data residency"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Premium$q$, $q$From roughly $51/agent/month$q$, $q$per agent, monthly or annual$q$, $q$["Everything in Standard","Asset and configuration management (CMDB)","AI-powered features via Atlassian Intelligence","Enhanced uptime SLA and 24/7 premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom contract$q$, $q$["Available from 201+ agents","Cross-product analytics and data lake access","Advanced admin, security, and identity controls","Unlimited automation runs and multi-site management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jira Service Management (JSM) is Atlassian's IT service management and service desk platform, built on the same underlying engine as Jira Software. It grew out of Jira Service Desk, which Atlassian launched to bring lightweight, developer-friendly ticketing to IT teams, and was relaunched under the Jira Service Management name as Atlassian expanded it into a full ITSM suite with incident, problem, change, and asset management capabilities.$q$, $q$The core idea behind JSM is to connect the people requesting help (employees, customers, or other teams) with the people who resolve issues (IT, ops, HR, legal, facilities) inside a single queue-based system, while keeping technical teams inside the Jira workflows they already use for development work. Requests come in through a customizable self-service portal, email, chat, or API, get routed through configurable workflows and SLAs, and can be linked directly to the underlying Jira issues where engineers are already tracking bugs and releases.$q$, $q$Because it shares infrastructure with Jira Software and Confluence, JSM is most compelling for organizations that are already Atlassian customers, since it lets service, development, and knowledge management sit on one platform instead of stitching together separate tools for support and engineering.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$who-its-for$q$, $q$Who Jira Service Management Is For$q$, 2, ARRAY[$q$JSM is aimed at IT operations and support teams that need structured incident, problem, and change management without building an ITSM program from scratch. Organizations following ITIL-aligned processes benefit from JSM's built-in change calendars, approval workflows, and post-incident review templates, which map closely to standard ITSM terminology and practices.$q$, $q$It also suits companies that already run Jira Software for engineering, since JSM lets support tickets, incidents, and engineering work items live in the same product and be cross-referenced without custom integrations. DevOps-minded teams that want incidents to trigger linked bugs, deployments, or change requests get a natural fit here.$q$, $q$Beyond IT, JSM's service project templates extend to HR, legal, facilities, and general business teams that want a ticketing portal and SLA-driven queues for internal requests, making it a reasonable choice for organizations standardizing multiple internal service desks on one platform rather than buying separate tools for each department.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small teams or solo founders who just need a simple help desk inbox may find JSM's configuration surface (workflows, permission schemes, request types, SLAs) heavier than necessary compared to a lightweight helpdesk tool built for simplicity from day one.$q$, $q$Organizations with no existing investment in the Atlassian ecosystem should weigh the switching cost carefully; while JSM works as a standalone product, much of its value compounds when it's paired with Jira Software and Confluence, so teams on entirely different stacks may not see the same efficiency gains.$q$, $q$Teams that need highly specialized customer support features, such as deep omnichannel contact-center capabilities, live chat-first workflows, or consumer-facing helpdesk branding as the primary use case, are often better served by dedicated customer support platforms, since JSM's design center of gravity is internal/IT service management rather than external customer support.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$JSM covers the core ITSM disciplines: incident management with on-call style queues and major incident workflows, problem management for root-cause tracking, and change management with risk assessment and approval workflows designed to reduce failed changes. Configuration and asset management (CMDB) lets teams track hardware, software, and their relationships to incidents and changes.$q$, $q$Request handling is built around customizable request types, forms, and SLAs surfaced through a branded self-service portal, plus an embedded knowledge base powered by Confluence so agents and end users can find answers before opening a ticket. Automation rules allow no-code workflows for routine tasks like auto-assigning tickets, escalating breached SLAs, or notifying stakeholders.$q$, $q$More recently, Atlassian has layered AI capabilities (Atlassian Intelligence) into JSM for things like summarizing tickets, suggesting responses, and virtual-agent style deflection in the help center, alongside deep integration with Jira Software issues, Confluence pages, Opsgenie-style alerting, and a marketplace of third-party apps for extending reporting, forms, and integrations.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$experience$q$, $q$The Jira Service Management Experience$q$, 2, ARRAY[$q$Day to day, agents work primarily from queues, which are filtered, prioritized lists of tickets configured per team, alongside a board and SLA countdown views similar to what Jira Software users already know. Admins configure request types, workflows, and permission schemes through the same project-settings model used across Jira, which shortens the learning curve for existing Atlassian admins but adds setup overhead for teams new to the ecosystem.$q$, $q$End users interact through a help center portal that can host multiple service projects (IT, HR, facilities) behind one front door, submitting requests through structured forms rather than free-text tickets, which tends to improve the quality of information agents receive up front.$q$, $q$Because JSM inherits Jira's configuration depth, first-time setup usually benefits from some upfront planning around workflows, SLAs, and permission schemes; once configured, though, teams generally find the day-to-day agent and requester experience straightforward, with most of the complexity front-loaded into initial administration rather than daily use.$q$]::text[], 4);
